def decode_source(key):
    return zlib.decompress(base64.b64decode(SOURCE_B64[key])).decode('utf-8')

def translate_source(source, lang):
    # Same code/script/font handling for every language as in Ukrainian.
    # Only visible text is translated.

    # Slider labels for saturation currents: use I_Dsat and I_Qsat everywhere.
    # The labels are written in mathtext so they appear as I with Dsat/Qsat subscript,
    # matching the original slider style but without old i_d0 / i_q0 text.
    slider_label_map = {
        'r"$i_d0 $"': 'r"$I_{Dsat}$"',
        'r"$i_q0 $"': 'r"$I_{Qsat}$"',
        "r'$i_d0 $'": "r'$I_{Dsat}$'",
        "r'$i_q0 $'": "r'$I_{Qsat}$'",
        '"$i_d0 $"': '"$I_{Dsat}$"',
        '"$i_q0 $"': '"$I_{Qsat}$"',
        "'$i_d0 $'": "'$I_{Dsat}$'",
        "'$i_q0 $'": "'$I_{Qsat}$'",
        'i_d0': 'I_Dsat',
        'i_q0': 'I_Qsat',
        'id0': 'I_Dsat',
        'iq0': 'I_Qsat',
    }
    for old, new in sorted(slider_label_map.items(), key=lambda x: len(x[0]), reverse=True):
        source = source.replace(old, new)

    if lang == 'uk':
        # Ukrainian must stay in the original Cyrillic SI style.
        # Only normalize accidental Latin-H torque spelling to Cyrillic Н.
        uk_unit_map = {
            'H*м': 'Н⋅м',
            'H⋅м/A': 'Н⋅м/А',
            'H⋅м/А': 'Н⋅м/А',
            'H⋅м/В': 'Н⋅м/В',
            'H⋅м/V': 'Н⋅м/В',
            'H⋅м': 'Н⋅м',
            'N⋅м': 'Н⋅м',
            'N*м': 'Н⋅м',
        }
        for old, new in sorted(uk_unit_map.items(), key=lambda x: len(x[0]), reverse=True):
            source = source.replace(old, new)
    else:
        # Non-Ukrainian modes use Latin/Roman SI symbols.
        unit_map = {
            'Вб': 'Wb', 'Wб': 'Wb',
            'ВАр': 'Var', 'ВАР': 'Var', 'VАр': 'Var',
            'ВА': 'VA', 'ВA': 'VA',
            'Вт': 'W',
            'Гн': 'H',
            'Ом': 'Ω',
            'рад/с': 'rad/s',
            'Н*м': 'N⋅m', 'H*м': 'N⋅m', 'N*m': 'N⋅m',
            'Н⋅м': 'N⋅m', 'H⋅м': 'N⋅m', 'N⋅м': 'N⋅m',
            'Н⋅м/А': 'N⋅m/A', 'H⋅м/A': 'N⋅m/A', 'H⋅м/А': 'N⋅m/A', 'N⋅м/А': 'N⋅m/A',
            'Н⋅м/В': 'N⋅m/V', 'H⋅м/В': 'N⋅m/V', 'H⋅м/V': 'N⋅m/V', 'N⋅м/В': 'N⋅m/V',
            'T/В': 'T/V', 'T/А': 'T/A',
            '"В"': '"V"', "'В'": "'V'",
            '"А"': '"A"', "'А'": "'A'",
            '/В': '/V', '/А': '/A',
            ' В': ' V', ' А': ' A',
            'В)': 'V)', 'А)': 'A)',
        }
        for old, new in sorted(unit_map.items(), key=lambda x: len(x[0]), reverse=True):
            source = source.replace(old, new)

        mapping = TRANSLATIONS.get(lang, {})
        for old in sorted(mapping.keys(), key=len, reverse=True):
            source = source.replace(old, mapping[old])

    # For Chinese/Japanese/Korean only:
    # keep the original base font and all original font sizes from the child code,
    # but switch only real CJK words to an appropriate CJK font at draw time.
    if lang in ('zh', 'ja', 'ko'):
        source = patch_child_cjk_fonts(source, lang)

    return source


def build_cjk_font_patch(lang):
    cjk_candidates = {
        'zh': ['Microsoft YaHei', 'SimHei', 'Noto Sans CJK SC', 'Noto Sans SC', 'Arial Unicode MS'],
        'ja': ['Yu Gothic', 'Meiryo', 'MS Gothic', 'Noto Sans CJK JP', 'Noto Sans JP', 'Arial Unicode MS'],
        'ko': ['Malgun Gothic', 'Gulim', 'Batang', 'Noto Sans CJK KR', 'Noto Sans KR', 'Arial Unicode MS'],
    }.get(lang, ['Arial Unicode MS'])

    return f"""front_properties = get_font_properties('Times New Romans')

# CJK font rule:
# - numbers, SI units, Latin letters, Greek symbols, and math text keep the same base font
#   and the same sizes as the original Ukrainian/English/German code.
# - only actual Chinese/Japanese/Korean characters are drawn with the appropriate CJK font.
def _available_font_names_for_cjk_patch():
    names = set()
    for _f in fm.findSystemFonts(fontpaths=None, fontext='ttf'):
        try:
            names.add(fm.FontProperties(fname=_f).get_name())
        except Exception:
            pass
    return names

_CJK_AVAILABLE_FONTS = _available_font_names_for_cjk_patch()


def _pick_cjk_font(_candidates):
    for _name in _candidates:
        if _name in _CJK_AVAILABLE_FONTS:
            return _name
    return _candidates[0]


_BASE_UI_FONT_FAMILY = front_properties.get_family()
_CJK_UI_FONT_FAMILY = [_pick_cjk_font({cjk_candidates!r})]


def _contains_cjk_chars(_text):
    _text = str(_text)
    for _ch in _text:
        _code = ord(_ch)
        if (
            0x4E00 <= _code <= 0x9FFF or      # CJK Unified Ideographs
            0x3400 <= _code <= 0x4DBF or      # CJK Extension A
            0x3040 <= _code <= 0x309F or      # Hiragana
            0x30A0 <= _code <= 0x30FF or      # Katakana
            0x31F0 <= _code <= 0x31FF or      # Katakana Phonetic Extensions
            0xAC00 <= _code <= 0xD7AF or      # Hangul syllables
            0x1100 <= _code <= 0x11FF or      # Hangul Jamo
            0x3130 <= _code <= 0x318F         # Hangul Compatibility Jamo
        ):
            return True
    return False


try:
    mpl.rcParams['font.family'] = _BASE_UI_FONT_FAMILY
    mpl.rcParams['axes.unicode_minus'] = False
except Exception:
    pass

try:
    from matplotlib.text import Text as _MplText
    if not getattr(_MplText, '_cjk_family_patch_installed', False):
        _ORIGINAL_MPL_TEXT_DRAW = _MplText.draw

        def _draw_with_cjk_family_patch(self, renderer):
            try:
                if _contains_cjk_chars(self.get_text()):
                    self.set_fontfamily(_CJK_UI_FONT_FAMILY)
                else:
                    self.set_fontfamily(_BASE_UI_FONT_FAMILY)
            except Exception:
                pass
            return _ORIGINAL_MPL_TEXT_DRAW(self, renderer)

        _MplText.draw = _draw_with_cjk_family_patch
        _MplText._cjk_family_patch_installed = True
except Exception:
    pass"""


def patch_child_cjk_fonts(source, lang):
    patch = build_cjk_font_patch(lang)
    replacements = 0
    for marker in (
        "front_properties = get_font_properties('Times New Romans')",
        "front_properties = get_font_properties('Times New Roman')",
    ):
        if marker in source:
            source = source.replace(marker, patch)
            replacements += 1
    return source


def run_script(script_text):
    fd, path = tempfile.mkstemp(prefix='combined_motor_mode_', suffix='.py', text=True)
    try:
        with os.fdopen(fd, 'w', encoding='utf-8') as f:
            f.write(script_text)

        # Important for PyInstaller EXE builds:
        # In a frozen app sys.executable is the built .exe, not python.exe.
        # Therefore subprocess.run([sys.executable, path]) will not open the generated
        # child .py module correctly. Run the child module inside the same process.
        old_argv = sys.argv[:]
        child_globals = {
            '__name__': '__main__',
            '__file__': path,
            '__package__': None,
            '__builtins__': __builtins__,
        }
        try:
            sys.argv = [path]
            exec(compile(script_text, path, 'exec'), child_globals)
        except SystemExit:
            pass
        finally:
            sys.argv = old_argv
            try:
                import matplotlib.pyplot as plt
                plt.close('all')
            except Exception:
                pass

    finally:
        try:
            os.remove(path)
        except OSError:
            pass


def show_main_menu(start_motor='round', start_flag='Ukraine'):
    import matplotlib as mpl
    mpl.rcParams['toolbar'] = 'None'
    mpl.rcParams["mathtext.fontset"] = "stix"

    import numpy as np
    import matplotlib.pyplot as plt
    from matplotlib.widgets import Button
    from matplotlib.animation import FuncAnimation
    from matplotlib.patches import Circle, Rectangle, Polygon, Ellipse, FancyArrowPatch
    from matplotlib.lines import Line2D
    import matplotlib.font_manager as fm

    FS = 9

    # =========================
    # ——— Visual layout params
    # =========================
    FIG_SIZE = (12, 6)

    # =========================
    # ——— Main palette
    # =========================
    Thegrey       = '#D3D3D3'
    Thebackground = '#E8E8E8'
    Thedark       = '#2F2F2F'
    Theblue       = '#4F6D8C'
    Thegreen      = '#4F6D4F'
    Thered        = '#8C4F4F'
    Thebeige      = '#FFF2E7'

    # =========================
    # ——— Typography
    # =========================
    def get_font_properties(font_name):
        fonts = fm.findSystemFonts(fontpaths=None, fontext='ttf')
        available = []
        for f in fonts:
            try:
                available.append(fm.FontProperties(fname=f).get_name())
            except Exception:
                pass
        if font_name in available:
            return fm.FontProperties(family=font_name)
        return fm.FontProperties(family='serif')

    front_properties = get_font_properties('Times New Roman')

    # =========================
    # ——— Styling helpers
    # =========================
    def set_font_everywhere(ax_obj, size=None):
        for lab in ax_obj.get_xticklabels() + ax_obj.get_yticklabels():
            lab.set_fontproperties(front_properties)
            if size is not None:
                lab.set_fontsize(size)
        ax_obj.xaxis.label.set_fontproperties(front_properties)
        ax_obj.yaxis.label.set_fontproperties(front_properties)
        ax_obj.title.set_fontproperties(front_properties)

    def style_axes_frame(a, edge=Thegrey, lw=1.5):
        for sp in a.spines.values():
            sp.set_edgecolor(edge)
            sp.set_linewidth(lw)
        a.tick_params(color=edge)
        set_font_everywhere(a)

    def style_button_frame(btn, edge=Thegrey, lw=1.5):
        bax = btn.ax
        bax.patch.set_edgecolor(edge)
        bax.patch.set_linewidth(lw)
        for sp in bax.spines.values():
            sp.set_edgecolor(edge)
            sp.set_linewidth(lw)
        set_font_everywhere(bax)

    # =========================
    # ——— Figure
    # =========================
    fig = plt.figure(figsize=FIG_SIZE)
    fig.patch.set_facecolor(Thebackground)

    try:
        fig.canvas.manager.set_window_title('')
    except Exception:
        pass

    try:
        mgr = fig.canvas.manager
        if hasattr(mgr, "toolbar") and mgr.toolbar is not None:
            tb = mgr.toolbar
            if hasattr(tb, "setVisible"):
                tb.setVisible(False)
            if hasattr(tb, "pack_forget"):
                tb.pack_forget()
            if hasattr(tb, "destroy"):
                tb.destroy()
    except Exception:
        pass

    # =========================
    # ——— Center motor square-button + two menu buttons
    # =========================
    motor_mode = start_motor   # 'round' = PMSM/synchronous, 'oval' = SynRM

    btn_w = 0.18
    btn_h = 0.11
    btn_gap = 0.03
    btn_x = 0.5 - btn_w / 2.0

    # Visually square motor button: normalized height is corrected by figure aspect.
    motor_box_w = btn_w
    motor_box_h = btn_w * (FIG_SIZE[0] / FIG_SIZE[1])

    stack_top = 0.825
    pos_motor = [btn_x, stack_top - motor_box_h, motor_box_w, motor_box_h]
    pos_btn_1 = [btn_x, pos_motor[1] - btn_gap - btn_h, btn_w, btn_h]
    pos_btn_2 = [btn_x, pos_btn_1[1] - btn_gap - btn_h, btn_w, btn_h]

    ax_motor = fig.add_axes(pos_motor, facecolor='white')
    ax_motor.set_zorder(10)
    style_axes_frame(ax_motor, Thegrey, 1.5)
    motor_hover = {'active': False}

    def motor_button_face():
        return 'lightgrey' if motor_hover['active'] else 'white'

    ax_btn_1 = plt.axes(pos_btn_1, facecolor='white')
    ax_btn_2 = plt.axes(pos_btn_2, facecolor='white')

    for a in (ax_btn_1, ax_btn_2):
        style_axes_frame(a, Thegrey, 1.5)

    btn_1 = Button(ax_btn_1, 'V(σ)/I(γ)', color='white', hovercolor='lightgrey')
    btn_2 = Button(ax_btn_2, 'MTPA/MTPV', color='white', hovercolor='lightgrey')

    for b in (btn_1, btn_2):
        b.label.set_fontproperties(front_properties)
        b.label.set_fontsize(FS + 6)
        b.label.set_color('black')
        style_button_frame(b, Thegrey, 1.5)

    # =========================
    # ——— Animated motor inside the square button
    # =========================
    base_angles_deg = [0.0, 120.0, 240.0]
    stator_circle_distance = 2.08
    stator_circle_radius = 0.25
    rotor_marker_radius = 0.115
    edge_gap = 0.035
    sigma_animation_deg = 0.0  # requested: animation σ must be 0

    def setup_motor_ax():
        ax_motor.clear()
        ax_motor.set_xlim(-3.0, 3.0)
        ax_motor.set_ylim(-3.0, 3.0)
        ax_motor.set_aspect('equal', adjustable='box')
        ax_motor.set_xticks([])
        ax_motor.set_yticks([])
        ax_motor.set_facecolor(motor_button_face())
        style_axes_frame(ax_motor, Thegrey, 1.5)

    def draw_cross(ax, x, y, r, color, lw=1.5, zorder=8):
        c45 = np.cos(np.deg2rad(45.0))
        s45 = np.sin(np.deg2rad(45.0))
        u = np.array([c45, s45])
        v = np.array([-s45, c45])
        p1a = np.array([x, y]) - r * u
        p1b = np.array([x, y]) + r * u
        p2a = np.array([x, y]) - r * v
        p2b = np.array([x, y]) + r * v
        ax.add_line(Line2D([p1a[0], p1b[0]], [p1a[1], p1b[1]], color=color, linewidth=lw, zorder=zorder))
        ax.add_line(Line2D([p2a[0], p2b[0]], [p2a[1], p2b[1]], color=color, linewidth=lw, zorder=zorder))

    def rot2d(vec, deg):
        th = np.deg2rad(deg)
        c, s = np.cos(th), np.sin(th)
        x, y = vec
        return np.array([c*x - s*y, s*x + c*y])

    def unit(vec, eps=1e-12):
        n = np.hypot(vec[0], vec[1])
        if n < eps:
            return np.array([1.0, 0.0]), 0.0
        return vec / n, n

    def ellipse_boundary_point(t_deg, a, b, rotor_angle_deg):
        t = np.deg2rad(t_deg)
        x_local = a * np.cos(t)
        y_local = b * np.sin(t)
        ca = np.cos(np.deg2rad(rotor_angle_deg))
        sa = np.sin(np.deg2rad(rotor_angle_deg))
        return np.array([ca * x_local - sa * y_local, sa * x_local + ca * y_local])

    def draw_grey_rotor_axis(theta_deg, length):
        th = np.deg2rad(theta_deg)
        end = np.array([length * np.cos(th), length * np.sin(th)])
        arr = FancyArrowPatch(
            posA=(0.0, 0.0), posB=(end[0], end[1]),
            arrowstyle='wedge', mutation_scale=18,
            linewidth=0.45, color=Thegrey, alpha=1.0,
            zorder=5
        )
        ax_motor.add_patch(arr)

    def draw_stator_phase_circles(animation_angle_rad):
        # Six colored phase circles. Dot/cross magnitude grows from zero to full circle radius.
        color_by_base = {0.0: Theblue, 120.0: Thegreen, 240.0: Thered}
        phase_shift_by_base = {0.0: 0.0, 120.0: 2.0*np.pi/3.0, 240.0: 4.0*np.pi/3.0}

        for base_ang in base_angles_deg:
            phase_value = np.sin(animation_angle_rad + phase_shift_by_base[base_ang])
            scale = min(abs(phase_value), 1.0)
            col = color_by_base[base_ang]

            for side_sign in (-90.0, +90.0):
                side_ang = base_ang + side_sign
                th = np.deg2rad(side_ang)
                x = stator_circle_distance * np.cos(th)
                y = stator_circle_distance * np.sin(th)

                coil = Circle((x, y), stator_circle_radius, fill=False, linewidth=1.5, edgecolor=col, zorder=7)
                ax_motor.add_patch(coil)

                is_left = (side_sign == -90.0)
                show_dot = (phase_value >= 0 and not is_left) or (phase_value < 0 and is_left)
                marker_r = stator_circle_radius * scale

                if show_dot:
                    dot = Circle((x, y), marker_r, facecolor=col, edgecolor='none', zorder=8)
                    ax_motor.add_patch(dot)
                else:
                    draw_cross(ax_motor, x, y, marker_r, col, lw=1.5, zorder=8)

    def draw_rotor_half_markers(rotor_shape, rotor_angle_deg):
        # PMSM rotor field markers only. Dot/cross is fixed at half circle radius.
        marker_color = Thedark
        inner_r = 0.50 * rotor_marker_radius
        inward_shift = rotor_marker_radius + edge_gap
        marker_shift = rotor_angle_deg

        cross_angles_deg = [15, 45, 75, 105, 135, 165]
        dot_angles_deg   = [-15, -45, -75, -105, -135, -165]

        if rotor_shape == 'round':
            rotor_radius = 1.46
            def point_on_rotor(tdeg):
                th = np.deg2rad(tdeg + marker_shift)
                u = np.array([np.cos(th), np.sin(th)])
                return (rotor_radius - inward_shift) * u
        else:
            # Not used for SynRM, because black PMSM rotor markers are hidden in SynRM mode.
            a = 1.36
            b = 0.78
            def point_on_rotor(tdeg):
                boundary = ellipse_boundary_point(tdeg, a, b, marker_shift)
                n = np.hypot(boundary[0], boundary[1])
                u = boundary / (n if n > 1e-12 else 1.0)
                return boundary - inward_shift * u

        for tdeg in cross_angles_deg:
            pos = point_on_rotor(tdeg)
            circ = Circle(pos, rotor_marker_radius, fill=False, linewidth=1.25, edgecolor=marker_color, zorder=7)
            ax_motor.add_patch(circ)
            draw_cross(ax_motor, pos[0], pos[1], inner_r, marker_color, lw=1.25, zorder=8)

        for tdeg in dot_angles_deg:
            pos = point_on_rotor(tdeg)
            circ = Circle(pos, rotor_marker_radius, fill=False, linewidth=1.25, edgecolor=marker_color, zorder=7)
            dot = Circle(pos, inner_r, facecolor=marker_color, edgecolor='none', zorder=8)
            ax_motor.add_patch(circ)
            ax_motor.add_patch(dot)

    def update_motor_animation(frame):
        setup_motor_ax()
        t = frame / 45.0

        # The same rotating reference principle as in the animation source,
        # but with σ fixed at 0 and without flux/resultant phase arrows.
        total = np.zeros(2)
        for i_idx, a_deg in enumerate(base_angles_deg):
            phase = np.deg2rad(i_idx * 120.0)
            mag = np.sin(t + phase)
            direction = np.deg2rad(a_deg)
            total += np.array([mag*np.cos(direction), mag*np.sin(direction)])
        u1, n1 = unit(total)
        if n1 <= 1e-9:
            u1 = np.array([1.0, 0.0])
        rotor_axis = rot2d(u1, sigma_animation_deg + 90.0)
        rotor_angle = np.degrees(np.arctan2(rotor_axis[1], rotor_axis[0]))
        rotor_visual_angle = rotor_angle + 90.0  # requested: rotor turned 90° counterclockwise

        outer = Circle((0, 0), 2.55, fill=False, linewidth=1.5, edgecolor=Thedark, zorder=1)
        inner = Circle((0, 0), 1.62, fill=False, linewidth=1.5, edgecolor=Thedark, zorder=1)
        ax_motor.add_patch(outer)
        ax_motor.add_patch(inner)

        if motor_mode == 'round':
            rotor_radius = 1.46
            rotor = Circle((0, 0), rotor_radius, facecolor=motor_button_face(), edgecolor=Thedark, linewidth=1.5, zorder=2)
            ax_motor.add_patch(rotor)
            axis_angles = [rotor_visual_angle, rotor_visual_angle + 90.0, rotor_visual_angle + 180.0, rotor_visual_angle + 270.0]
            axis_lengths = [rotor_radius, rotor_radius, rotor_radius, rotor_radius]
            rotor_shape = 'round'
        else:
            rotor_a = 1.46
            rotor_b = 0.90
            rotor = Ellipse(
                (0, 0), width=2.0*rotor_a, height=2.0*rotor_b, angle=rotor_visual_angle,
                facecolor=motor_button_face(), edgecolor=Thedark, linewidth=1.5, zorder=2
            )
            ax_motor.add_patch(rotor)
            axis_angles = [rotor_visual_angle, rotor_visual_angle + 90.0, rotor_visual_angle + 180.0, rotor_visual_angle + 270.0]
            axis_lengths = [rotor_a, rotor_b, rotor_a, rotor_b]
            rotor_shape = 'oval'

        # Four grey arrows remain in both PMSM and SynRM modes.
        for ang, ln in zip(axis_angles, axis_lengths):
            draw_grey_rotor_axis(ang, ln)

        draw_stator_phase_circles(t)

        # Black rotor circles with dots/crosses are present only for PMSM.
        if motor_mode == 'round':
            draw_rotor_half_markers(rotor_shape, rotor_visual_angle)

        return ax_motor.patches + ax_motor.lines

    ani_motor = FuncAnimation(fig, update_motor_animation, frames=np.arange(0, 1000000), interval=30, blit=False)

    LANG_BY_FLAG = {
        'Ukraine': 'uk',
        'Great Britain': 'en',
        'Germany': 'de',
        'China': 'zh',
        'Japan': 'ja',
        'Korea': 'ko',
    }

    MENU_TEXT = {
        'uk': {'vi': 'V(σ)/I(γ)', 'mtpa': 'MTPA/MTPV'},
        'en': {'vi': 'V(σ)/I(γ)', 'mtpa': 'MTPA/MTPV'},
        'de': {'vi': 'V(σ)/I(γ)', 'mtpa': 'MTPA/MTPV'},
        'zh': {'vi': 'V(σ)/I(γ)', 'mtpa': 'MTPA/MTPV'},
        'ja': {'vi': 'V(σ)/I(γ)', 'mtpa': 'MTPA/MTPV'},
        'ko': {'vi': 'V(σ)/I(γ)', 'mtpa': 'MTPA/MTPV'},
    }

    def current_lang():
        return LANG_BY_FLAG.get(current_flag, 'uk')

    def update_menu_language():
        t = MENU_TEXT.get(current_lang(), MENU_TEXT['uk'])
        btn_1.label.set_text(t['vi'])
        btn_2.label.set_text(t['mtpa'])
        for b in (btn_1, btn_2):
            b.label.set_fontproperties(front_properties)
            b.label.set_fontsize(FS + 6)
